<?php
namespace App\Http\Controllers;use App\Models\{Article,Banner,Brand,Category,HomeSection,Product,Slider};use Illuminate\View\View;
class HomeController extends Controller{public function __invoke():View{$sections=HomeSection::where('is_active',1)->orderBy('sort_order')->get()->keyBy('key');return view('pages.home',['sections'=>$sections,'sliders'=>Slider::where('is_active',1)->where('show_desktop',1)->orderBy('sort_order')->get(),'categories'=>Category::where('is_active',1)->where('show_in_home',1)->orderBy('sort_order')->take(8)->get(),'featuredProducts'=>Product::with('category')->where('is_active',1)->where('is_featured',1)->take(12)->get(),'bestSellers'=>Product::where('is_active',1)->where(fn($q)=>$q->where('is_best_selling',1)->orWhere('sales_count','>',0))->orderByDesc('sales_count')->take(8)->get(),'latestProducts'=>Product::where('is_active',1)->latest()->take(8)->get(),'articles'=>Article::where('is_active',1)->where('show_in_home',1)->latest()->take(3)->get(),'brands'=>Brand::where('is_active',1)->where('show_in_home',1)->orderBy('sort_order')->take(10)->get(),'banners'=>Banner::where('is_active',1)->orderBy('sort_order')->get()->groupBy('position')]);}}
